code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, icon } from 'decantr/components';

code.example:
function BentoFeatures({ hero, stats, features }) {
  const { div, h2, h3, p, span } = tags;

  return div({ class: css('_flex _col _gap6 _py12 _px6 _mw[1100px] _mx[auto]') },
    // Hero feature card
    Card({ class: css('d-glass _p6') },
      Card.Body({ class: css('_grid _gc1 _lg:gc2 _gap6 _aic') },
        div({ class: css('_flex _col _gap4') },
          Badge({ variant: 'outline' }, hero.badge),
          h2({ class: css('_heading2') }, hero.title),
          p({ class: css('_fgmuted _lh[1.6]') }, hero.description)
        ),
        div({ class: css('d-glass-strong _r3 _p4 _hfull') }, hero.preview)
      )
    ),
    // Stats row
    div({ class: css('_grid _gc2 _md:gc4 _gap4') },
      ...stats.map(s =>
        Card({ class: css('d-glass _tc _p4') },
          Card.Body({ class: css('_flex _col _gap2 _aic') },
            icon(s.icon, { class: css('_fgprimary') }),
            span({ class: css('_heading2 _fgfg') }, s.value),
            span({ class: css('_textsm _fgmuted') }, s.label)
          )
        )
      )
    ),
    // Features row
    div({ class: css('_grid _gc1 _md:gc3 _gap4') },
      ...features.map(f =>
        Card({ class: css('d-glass') },
          Card.Body({ class: css('_flex _col _gap3') },
            div({ class: css('_w10 _h10 _r2 _bgprimary/10 _flex _aic _jcc _fgprimary') }, icon(f.icon)),
            h3({ class: css('_heading5') }, f.title),
            p({ class: css('_textsm _fgmuted') }, f.description)
          )
        )
      )
    )
  );
}

